<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { ApiError, apiRequest, authState } from '../auth'
import type { SaasPlan, TenantOverview } from '../saas'
import AppShell from '../components/AppShell.vue'

const plans = ref<SaasPlan[]>([]); const tenants = ref<TenantOverview[]>([]); const error = ref(''); const message = ref(''); const grantToken = ref('')
const plan = reactive({ code: '', name: '', employee_limit: 20, card_limit: 20, storage_limit_bytes: 1073741824, is_active: true })
const change = reactive({ company_id: '', plan_id: '', expires_at: '' }); const support = reactive({ company_id: '', reason: '', hours: 1 })
async function load() { try { [plans.value, tenants.value] = await Promise.all([apiRequest<SaasPlan[]>('/platform/saas/plans'), apiRequest<TenantOverview[]>('/platform/saas/tenants')]) } catch (e) { error.value = e instanceof ApiError ? e.message : 'SaaS 运营数据加载失败' } }
async function createPlan() { try { await apiRequest('/platform/saas/plans', { method: 'POST', body: JSON.stringify(plan) }); message.value = '套餐已创建'; await load() } catch (e) { error.value = e instanceof ApiError ? e.message : '套餐创建失败' } }
async function updateSubscription() { try { await apiRequest(`/platform/saas/tenants/${change.company_id}/subscription`, { method: 'PUT', body: JSON.stringify({ plan_id: change.plan_id, expires_at: new Date(change.expires_at).toISOString(), note: '平台运营调整' }) }); message.value = '套餐和有效期已即时生效'; await load() } catch (e) { error.value = e instanceof ApiError ? e.message : '订阅调整失败' } }
async function suspend(item: TenantOverview) { await apiRequest(`/platform/companies/${item.company_id}/status`, { method: 'PATCH', body: JSON.stringify({ status: item.company_status === 'active' ? 'suspended' : 'active' }) }); await load() }
async function cancel(item: TenantOverview) { const code = window.prompt('请输入企业编号确认注销申请。系统将进入 7 天冷静期，不会立即删除数据。'); if (!code) return; try { await apiRequest(`/platform/saas/tenants/${item.company_id}/cancel`, { method: 'POST', body: JSON.stringify({ confirmation: code, cooling_days: 7 }) }); await load() } catch (e) { error.value = e instanceof ApiError ? e.message : '注销申请失败' } }
async function createGrant() { if (!authState.user) return; const expires = new Date(Date.now() + support.hours * 3600000); try { const result = await apiRequest<{ token: string }>('/platform/saas/support-grants', { method: 'POST', body: JSON.stringify({ company_id: support.company_id, granted_to_user_id: authState.user.id, reason: support.reason, expires_at: expires.toISOString() }) }); grantToken.value = result.token; message.value = '临时授权已创建，请妥善保存一次性令牌' } catch (e) { error.value = e instanceof ApiError ? e.message : '授权创建失败' } }
const percentage = (used: number, limit: number) => limit ? Math.min(100, Math.round(used / limit * 100)) : 0
onMounted(load)
</script>

<template><AppShell><header class="page-header compact"><div><p class="eyebrow">SAAS OPERATIONS</p><h1>SaaS 运营与套餐配额</h1><p>管理租户订阅、资源用量、异常状态、注销冷静期和临时协助授权。</p></div></header><div v-if="message" class="notice success">{{ message }}</div><div v-if="error" class="notice error">{{ error }}</div><section class="settings-grid"><form class="panel form-stack" @submit.prevent="createPlan"><h2>创建套餐</h2><label><span>套餐编号</span><input v-model.trim="plan.code" required /></label><label><span>套餐名称</span><input v-model.trim="plan.name" required /></label><div class="modal-grid"><label><span>员工数</span><input v-model.number="plan.employee_limit" type="number" min="1" /></label><label><span>名片数</span><input v-model.number="plan.card_limit" type="number" min="1" /></label><label><span>存储字节数</span><input v-model.number="plan.storage_limit_bytes" type="number" min="1" /></label></div><button class="primary-button">创建套餐</button></form><form class="panel form-stack" @submit.prevent="updateSubscription"><h2>调整租户订阅</h2><label><span>租户</span><select v-model="change.company_id" required><option value="">请选择</option><option v-for="item in tenants" :key="item.company_id" :value="item.company_id">{{ item.company_name }}</option></select></label><label><span>套餐</span><select v-model="change.plan_id" required><option value="">请选择</option><option v-for="item in plans.filter(p => p.is_active)" :key="item.id" :value="item.id">{{ item.name }}</option></select></label><label><span>到期时间</span><input v-model="change.expires_at" type="datetime-local" required /></label><button class="primary-button">即时生效</button></form></section><section class="panel table-panel"><h2>租户使用概览</h2><table><thead><tr><th>企业</th><th>订阅</th><th>员工</th><th>名片</th><th>存储</th><th>提醒</th><th>操作</th></tr></thead><tbody><tr v-for="item in tenants" :key="item.company_id"><td><b>{{ item.company_name }}</b><small>{{ item.company_status }}</small></td><td>{{ item.subscription.plan_name }}<small>{{ item.subscription.status }} · {{ new Date(item.subscription.expires_at).toLocaleDateString() }}</small></td><td>{{ item.subscription.usage.employees }}/{{ item.subscription.limits.employees }}（{{ percentage(item.subscription.usage.employees, item.subscription.limits.employees) }}%）</td><td>{{ item.subscription.usage.cards }}/{{ item.subscription.limits.cards }}</td><td>{{ Math.round(item.subscription.usage.storage_bytes / 1048576) }}/{{ Math.round(item.subscription.limits.storage_bytes / 1048576) }} MB</td><td>{{ item.alerts.join('、') || '正常' }}</td><td class="actions"><button class="link-button" @click="suspend(item)">{{ item.company_status === 'active' ? '冻结' : '恢复' }}</button><button class="link-button danger" @click="cancel(item)">申请注销</button></td></tr></tbody></table></section><form class="panel form-stack" @submit.prevent="createGrant"><h2>临时协助授权</h2><p>授权只允许在期限内读取租户运营概览，每次访问都会写入平台日志。</p><div class="inline-form"><label><span>租户</span><select v-model="support.company_id" required><option value="">请选择</option><option v-for="item in tenants" :key="item.company_id" :value="item.company_id">{{ item.company_name }}</option></select></label><label><span>授权原因</span><input v-model.trim="support.reason" minlength="5" required /></label><label><span>有效小时</span><input v-model.number="support.hours" type="number" min="1" max="24" /></label><button class="primary-button">创建授权</button></div><code v-if="grantToken">{{ grantToken }}</code></form></AppShell></template>
